 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
 5	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import LabelsModal from '@components/LabelsModal/LabelsModal';
 8	import LabelsViewDetailsItemContent from '@components/LabelsViewDetailsItemContent/LabelsViewDetailsItemContent';
 9	import { ADD, REPLACE } from '@components/ModalForm/utils/constants';
10	import { PlanModel, type V1beta1Plan } from '@kubev2v/types';
11	import { k8sPatch } from '@openshift-console/dynamic-plugin-sdk';
12	import { Stack, StackItem } from '@patternfly/react-core';
13	import { DOC_MAIN_HELP_LINK } from '@utils/links';
14	
15	import type { EditableDetailsItemProps } from '../../../utils/types';
16	
17	const TargetLabelsDetailsItem: FC<EditableDetailsItemProps> = ({ canPatch, plan }) => {
18	  const { t } = useForkliftTranslation();
19	  const { showModal } = useModal();
20	
21	  const TARGET_LABELS_DETAILS_ITEM_DESCRIPTION = t(
22	    'Specify custom labels that will be applied after migration to all target virtual machines of the migration plan. This can apply organizational or operational labels to migrated virtual machines for further identification and management.',
23	  );
24	
25	  const onConfirm: (newLabels: Record<string, string | null>) => Promise<V1beta1Plan> = async (
26	    newLabels: Record<string, string | null>,
27	  ) => {
28	    const currentValue = plan?.spec?.targetLabels;
29	    const op = currentValue ? REPLACE : ADD;
30	
31	    const result = await k8sPatch({
32	      data: [
33	        {
34	          op,
35	          path: '/spec/targetLabels',
36	          value: newLabels,
37	        },
38	      ],
39	      model: PlanModel,
40	      resource: plan,
41	    });
42	
43	    return result;
44	  };
45	
46	  return (
47	    <DetailsItem
48	      testId="vm-target-labels-detail-item"
49	      title={t('VM target labels')}
50	      content={<LabelsViewDetailsItemContent labels={plan?.spec?.targetLabels} />}
51	      helpContent={TARGET_LABELS_DETAILS_ITEM_DESCRIPTION}
52	      crumbs={['spec', 'targetLabels']}
53	      moreInfoLink={DOC_MAIN_HELP_LINK}
54	      onEdit={() => {
55	        showModal(
56	          <LabelsModal
57	            initialLabels={plan?.spec?.targetLabels}
58	            description={
59	              <ForkliftTrans>
60	                <Stack hasGutter>
61	                  <StackItem>{TARGET_LABELS_DETAILS_ITEM_DESCRIPTION}</StackItem>
62	                  <StackItem>
63	                    Enter <strong>key=value</strong> pair(s). For example: project=myProject
64	                  </StackItem>
65	                </Stack>
66	              </ForkliftTrans>
67	            }
68	            title={t('Edit VM target labels')}
69	            onConfirm={onConfirm}
70	          />,
71	        );
72	      }}
73	      canEdit={canPatch && isPlanEditable(plan)}
74	    />
75	  );
76	};
77	
78	export default TargetLabelsDetailsItem;

